from dataclasses import dataclass, field
from enum import Enum


class TaskStatus(Enum):
    TODO = "todo"
    IN_PROGRESS = "in_progress"
    DONE = "done"
    BLOCKED = "blocked"


@dataclass
class WindDownTask:
    category: str
    description: str
    owner: str
    status: TaskStatus = TaskStatus.TODO
    blocker: str = ""

    def is_complete(self) -> bool:
        return self.status == TaskStatus.DONE


@dataclass
class WindDownSprint:
    initiative_id: str
    sprint_end_date: str
    tasks: list[WindDownTask] = field(default_factory=list)

    def add_task(self, task: WindDownTask) -> None:
        self.tasks.append(task)

    def completion_pct(self) -> float:
        if not self.tasks:
            return 0.0
        done = sum(1 for t in self.tasks if t.is_complete())
        return done / len(self.tasks) * 100

    def blocked_tasks(self) -> list[WindDownTask]:
        return [t for t in self.tasks if t.status == TaskStatus.BLOCKED]

    def is_ready_to_close(self) -> bool:
        return all(t.is_complete() for t in self.tasks)


sprint = WindDownSprint(initiative_id="INI-003", sprint_end_date="2026-07-22")
sprint.add_task(WindDownTask("Data", "Export corpus-v2 to s3://archive/search/", "Data Engineer", TaskStatus.DONE))
sprint.add_task(WindDownTask("Model", "Archive search-embedder-v1 checkpoint", "ML Engineer", TaskStatus.IN_PROGRESS))
sprint.add_task(WindDownTask("Endpoint", "Decommission /search/v1 endpoint", "Platform Engineer", TaskStatus.TODO))
sprint.add_task(WindDownTask("Docs", "Write sunset retrospective", "Tech Lead", TaskStatus.TODO))

print(f"Wind-Down Sprint: {sprint.completion_pct():.0f}% complete")
if sprint.blocked_tasks():
    for t in sprint.blocked_tasks():
        print(f"  BLOCKED: {t.description} — {t.blocker}")
print(f"Ready to close: {sprint.is_ready_to_close()}")
